<span class="line"><span style="color:#79B8FF;">AI_CHANNEL_HEX_COLORS</span><span style="color:#E1E4E8;">[</span><span style="color:#79B8FF;">1</span><span style="color:#E1E4E8;">];  </span><span style="color:#6A737D;">// &quot;#5ec8ff&quot;(青色)—— 通道 1</span></span>
